#include "interface.h"

#include <cstdint>
#include <vector>
#include <omp.h>

namespace {

static inline void sort_int32_inplace(int32_t* a, std::size_t n) {
  if (n < 2) return;

  std::vector<int32_t> buf(n);
  int32_t* src = a;
  int32_t* dst = buf.data();

  for (std::size_t width = 1; width < n; width <<= 1) {
    for (std::size_t left = 0; left < n; left += (width << 1)) {
      std::size_t mid = left + width;
      std::size_t right = left + (width << 1);
      if (mid > n) mid = n;
      if (right > n) right = n;

      std::size_t i = left;
      std::size_t j = mid;
      std::size_t k = left;

      while (i < mid && j < right) {
        if (src[i] <= src[j]) {
          dst[k++] = src[i++];
        } else {
          dst[k++] = src[j++];
        }
      }
      while (i < mid) dst[k++] = src[i++];
      while (j < right) dst[k++] = src[j++];
    }

    int32_t* tmp = src;
    src = dst;
    dst = tmp;
  }

  if (src != a) {
    for (std::size_t i = 0; i < n; ++i) a[i] = src[i];
  }
}

static inline int64_t sum_pairwise_abs_sorted(const int32_t* a, std::size_t n) {
  int64_t prefix = 0;
  int64_t total = 0;
  for (std::size_t i = 0; i < n; ++i) {
    const int64_t v = static_cast<int64_t>(a[i]);
    total += v * static_cast<int64_t>(i) - prefix;
    prefix += v;
  }
  return total;
}

}  // namespace

int64_t allpairs_l1_sum(const std::vector<int32_t>& xs, const std::vector<int32_t>& ys, int iters) {
  const std::size_t n = xs.size();
  if (iters <= 0 || n < 2) return 0;

  std::vector<int32_t> xsorted(xs.begin(), xs.end());
  std::vector<int32_t> ysorted(ys.begin(), ys.end());

  #pragma omp parallel sections
  {
    #pragma omp section
    {
      sort_int32_inplace(xsorted.data(), n);
    }
    #pragma omp section
    {
      sort_int32_inplace(ysorted.data(), n);
    }
  }

  int64_t xsum = 0;
  int64_t ysum = 0;

  #pragma omp parallel sections
  {
    #pragma omp section
    {
      xsum = sum_pairwise_abs_sorted(xsorted.data(), n);
    }
    #pragma omp section
    {
      ysum = sum_pairwise_abs_sorted(ysorted.data(), n);
    }
  }

  const int64_t total = xsum + ysum;
  (void)iters;
  return total;
}
